SourceCode.Declaration:
/// <summary>
/// Contract class for modifying unsold inventory transactions in the ETGSPAIN model.
/// </summary>
[
    DataContract
]
class ETGSPAINUnsoldInventTransModifyContract implements SysOperationValidatable
{
    ETGSPAINUnsoldQty   etgspainUnsoldQty;
    ETGSPAINUnsoldQty   etgspainMaxUnsoldQty;
    RefRecId            refRecId;
    boolean             updateMaxUnsoldQty;

}

Method.Source:
/// <summary>
/// Gets or sets the unsold quantity.
/// </summary>
/// <param name="_etgspainUnsoldQty">Unsold quantity</param>
/// <returns>Unsold quantity</returns>
[
    DataMember
]
public ETGSPAINUnsoldQty parmETGSPAINUnsoldQty(ETGSPAINUnsoldQty _etgspainUnsoldQty = etgspainUnsoldQty)
{
    etgspainUnsoldQty = _etgspainUnsoldQty;
    return etgspainUnsoldQty;
}

/// <summary>
/// Gets or sets the maximum allowed unsold quantity.
/// </summary>
/// <param name="_etgspainMaxUnsoldQty">Maximum unsold quantity</param>
/// <returns>Maximum unsold quantity</returns>
[
    DataMember,
    SysOperationLabel(literalStr("@ETGSPAINLabels:MaxUnsold"))
]
public ETGSPAINUnsoldQty parmETGSPAINMaxUnsoldQty(ETGSPAINUnsoldQty _etgspainMaxUnsoldQty = etgspainMaxUnsoldQty)
{
    etgspainMaxUnsoldQty = _etgspainMaxUnsoldQty;
    return etgspainMaxUnsoldQty;
}

/// <summary>
/// Gets or sets the reference record ID.
/// </summary>
/// <param name="_refRecId">Reference record ID</param>
/// <returns>Reference record ID</returns>
public RefRecId parmRefRecId(RefRecId _refRecId = refRecId)
{
    refRecId = _refRecId;
    return refRecId;
}

/// <summary>
/// Gets or sets the flag to update the maximum unsold quantity.
/// </summary>
/// <param name="_updateMaxUnsoldQty">Update maximum unsold quantity</param>
/// <returns>Boolean flag indicating whether to update the maximum unsold quantity</returns>
public boolean parmUpdateMaxUnsoldQty(boolean _updateMaxUnsoldQty = updateMaxUnsoldQty)
{
    updateMaxUnsoldQty = _updateMaxUnsoldQty;
    return updateMaxUnsoldQty;
}

/// <summary>
/// Validates the contract parameters.
/// </summary>
/// <returns>True if the parameters are valid, otherwise False</returns>
public boolean validate()
{
    boolean isValid = true;

    ETGSPAINUnsoldInventTrans etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(refRecId, true);

    if (!this.updateMaxUnsoldQty && ((etgspainUnsoldInventTrans.MaxUnsoldQty < 0 && etgspainUnsoldQty < 0 && abs(etgspainUnsoldQty) >= abs(etgspainUnsoldInventTrans.MaxUnsoldQty))
        || (etgspainUnsoldInventTrans.MaxUnsoldQty > 0 && etgspainUnsoldQty >= etgspainUnsoldInventTrans.MaxUnsoldQty)))
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:ETGSPAINUnsoldQtyValidateWarning", etgspainUnsoldInventTrans.MaxUnsoldQty));
    }

    return isValid;
}
